using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly string _dataPath;
    private ITransformer? _model;
    private PredictionEngine<TicketData, TicketPrediction>? _predictionEngine;
    private string[] _categoryNames = [];

    public bool IsTrained => _model is not null;

    public TicketClassifierService(IWebHostEnvironment env)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
    }

    public EvaluationResponse TrainAndEvaluate()
    {
        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Build the training pipeline:
        // 1. Combine Subject + Description into a single text feature
        // 2. Featurize the combined text
        // 3. Include Priority as a numeric feature
        // 4. Concatenate all features
        // 5. Map the label to a key and train with SdcaMaximumEntropy
        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With a small dataset, use cross-validation for robust evaluation
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(
            dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        // Train the final model on the full dataset
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract category names from the label key mapping
        var labelCol = dataView.Schema["Category"];
        var slotNames = new VBuffer<ReadOnlyMemory<char>>();
        var transformedData = _model.Transform(dataView);
        transformedData.Schema["Label"].GetKeyValues(ref slotNames);
        _categoryNames = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

        // Build per-class metrics from cross-validation
        var bestRun = cvResults.OrderByDescending(r => r.Metrics.MacroAccuracy).First();
        var metrics = bestRun.Metrics;

        var perClass = new List<PerClassMetric>();
        for (int i = 0; i < metrics.PerClassLogLoss.Count && i < _categoryNames.Length; i++)
        {
            perClass.Add(new PerClassMetric
            {
                Category = _categoryNames[i],
                Precision = i < metrics.PerClassLogLoss.Count ? Math.Round(1.0 - metrics.PerClassLogLoss[i], 4) : 0,
                Recall = 0,
                F1Score = 0
            });
        }

        // Compute per-class precision/recall/F1 by running predictions on training data
        var predictions = _model.Transform(dataView);
        var evalMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        var confusionMatrix = evalMetrics.ConfusionMatrix;
        perClass.Clear();
        for (int i = 0; i < confusionMatrix.PerClassPrecision.Count && i < _categoryNames.Length; i++)
        {
            double precision = confusionMatrix.PerClassPrecision[i];
            double recall = confusionMatrix.PerClassRecall[i];
            double f1 = (precision + recall) > 0
                ? 2 * precision * recall / (precision + recall)
                : 0;
            perClass.Add(new PerClassMetric
            {
                Category = _categoryNames[i],
                Precision = Math.Round(precision, 4),
                Recall = Math.Round(recall, 4),
                F1Score = Math.Round(f1, 4)
            });
        }

        return new EvaluationResponse
        {
            MacroAccuracy = (float)Math.Round(evalMetrics.MacroAccuracy, 4),
            MicroAccuracy = (float)Math.Round(evalMetrics.MicroAccuracy, 4),
            LogLoss = (float)Math.Round(evalMetrics.LogLoss, 4),
            LogLossReduction = (float)Math.Round(evalMetrics.LogLossReduction, 4),
            PerClassMetrics = perClass.ToArray()
        };
    }

    public PredictionResponse Predict(TicketRequest request)
    {
        if (_predictionEngine is null)
            throw new InvalidOperationException("Model has not been trained. Call POST /api/ticket-classifier/train first.");

        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionEngine.Predict(ticketData);

        var probabilities = new Dictionary<string, float>();
        for (int i = 0; i < _categoryNames.Length && i < prediction.Score.Length; i++)
        {
            probabilities[_categoryNames[i]] = (float)Math.Round(prediction.Score[i], 4);
        }

        return new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Probabilities = probabilities
        };
    }
}

