using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/ticket-classifier")]
public class TicketClassifierController : ControllerBase
{
    private readonly TicketClassifierService _service;

    public TicketClassifierController(TicketClassifierService service)
    {
        _service = service;
    }

    /// <summary>
    /// Trains the ML model on the CSV data and returns evaluation metrics.
    /// </summary>
    [HttpPost("train")]
    public ActionResult<EvaluationResponse> Train()
    {
        var metrics = _service.TrainAndEvaluate();
        return Ok(metrics);
    }

    /// <summary>
    /// Predicts the category for a support ticket.
